const fs = require('fs');

// --- Load context ---
let ctx = {};
try {
  ctx = JSON.parse(fs.readFileSync('/data/KAI_Context.json', 'utf8'));
} catch(e) {
  ctx = {};
}

// --- Read from context file (not hardcoded) ---
const rawDeadlines = ctx.deadlines || [];
const compliance   = ctx.compliance_rules || [];
const today        = new Date();
today.setHours(0, 0, 0, 0);

// --- Helpers ---
const isValidDate = s => /^\d{4}-\d{2}-\d{2}$/.test(s) && !isNaN(new Date(s).getTime());
const daysUntil   = s => Math.ceil((new Date(s) - today) / (1000 * 60 * 60 * 24));

// --- Filter: skip FILED/COMPLETE, skip non-date strings ---
// Dates determine urgency automatically. FILED/COMPLETE = done, hide it.
const deadlines = rawDeadlines.filter(d => {
  if (!d || !d.item || !d.date) return false;
  const st = (d.status || '').toUpperCase();
  if (st === 'FILED' || st === 'COMPLETE') return false;
  return isValidDate(d.date);
});

// --- Bucket by date (same logic as v2, unchanged) ---
const overdue  = deadlines.filter(d => daysUntil(d.date) < 0);
const critical = deadlines.filter(d => { const n = daysUntil(d.date); return n >= 0 && n <= 7; });
const urgent   = deadlines.filter(d => { const n = daysUntil(d.date); return n > 7  && n <= 21; });
const upcoming = deadlines.filter(d => { const n = daysUntil(d.date); return n > 21 && n <= 90; });

// --- Build full report (saved to file) ---
let report = `IRIS COMPLIANCE MONITOR v3\n`;
report    += `Generated: ${today.toLocaleString('en-US', {timeZone: 'America/New_York'})} EST\n`;
report    += `KAI_Context.json v${ctx.meta?.version || 'unknown'} loaded\n`;
report    += `Active: ${deadlines.length} | Filed/Complete skipped: ${rawDeadlines.length - deadlines.length}\n\n`;

if (overdue.length) {
  report += '🔴 OVERDUE:\n';
  overdue.forEach(d => { report += `  • ${d.item} — ${Math.abs(daysUntil(d.date))}d overdue [${d.entity}]\n`; });
  report += '\n';
}
if (critical.length) {
  report += '🚨 CRITICAL (7 days):\n';
  critical.forEach(d => { report += `  • ${d.item} — ${daysUntil(d.date)}d (${d.date}) [${d.entity}] Owner: ${d.owner}\n`; });
  report += '\n';
}
if (urgent.length) {
  report += '⚠️ URGENT (21 days):\n';
  urgent.forEach(d => { report += `  • ${d.item} — ${daysUntil(d.date)}d (${d.date}) [${d.entity}]\n`; });
  report += '\n';
}
if (upcoming.length) {
  report += '📅 UPCOMING (90 days):\n';
  upcoming.forEach(d => { report += `  • ${d.item} — ${daysUntil(d.date)}d (${d.date}) [${d.entity}]\n`; });
  report += '\n';
}
if (!overdue.length && !critical.length && !urgent.length) {
  report += '✅ No overdue, critical, or urgent items.\n\n';
}

report += `COMPLIANCE RULES:\n${compliance.map(r => '• ' + r).join('\n')}\n\n`;
report += `REGULATORY WATCH:\n`;
report += `• FAA Part 108 BVLOS final rule INCOMING — flagged for Atlas SBIR\n`;
report += `• FAA-2022-1258 BVLOS rulemaking active\n`;
report += `• OMB M-26-02 federal drone compliance deadline: 2026-05-20\n`;

// --- Save report ---
const outputPath = `/data/Aidan_Outputs/Iris/Iris_Report_${today.toISOString().replace(/[:.]/g, '-')}.txt`;
fs.mkdirSync('/data/Aidan_Outputs/Iris', { recursive: true });
fs.writeFileSync(outputPath, report, 'utf8');

// --- WhatsApp message (concise) ---
let whatsappMsg = 'Bot reply: IRIS COMPLIANCE REPORT\n\n';
if (overdue.length)  { whatsappMsg += `🔴 OVERDUE (${overdue.length}):\n`;   overdue.forEach(d  => { whatsappMsg += `• ${d.item}\n`; });              whatsappMsg += '\n'; }
if (critical.length) { whatsappMsg += `🚨 CRITICAL (${critical.length}):\n`; critical.forEach(d => { whatsappMsg += `• ${d.item} — ${daysUntil(d.date)}d\n`; }); whatsappMsg += '\n'; }
if (urgent.length)   { whatsappMsg += `⚠️ URGENT (${urgent.length}):\n`;     urgent.forEach(d   => { whatsappMsg += `• ${d.item} — ${daysUntil(d.date)}d\n`; }); }
whatsappMsg += '\nPart 108 BVLOS: INCOMING — flagged for Atlas.';

const summary = `IRIS COMPLETE\nCritical: ${critical.length} | Urgent: ${urgent.length} | Overdue: ${overdue.length}\nSaved: /data/Aidan_Outputs/Iris/`;

return [{ json: { report, whatsappMsg, summary, criticalCount: critical.length, urgentCount: urgent.length, overdueCount: overdue.length, savedTo: outputPath } }];

